abstract class PaymentProcessor {
    protected String merchantId;
    protected double feePercent;

    public PaymentProcessor(String merchantId, double feePercent) {
        if (merchantId == null || merchantId.isBlank()) throw new IllegalArgumentException("merchantId required");
        this.merchantId = merchantId;
        this.feePercent = feePercent;
    }

    public abstract void processPayment(double amount);
    public abstract String getProviderName();

    public double calculateFee(double amount) {
        return amount * feePercent / 100;
    }

    public void printSummary(double amount) {
        double fee = calculateFee(amount);
        System.out.println(getProviderName() + " fee: ₹" + fee + " | Net: ₹" + (amount - fee));
    }
}

class StripeProcessor extends PaymentProcessor {
    public StripeProcessor(String merchantId) { super(merchantId, 2.0); }

    @Override
    public void processPayment(double amount) {
        System.out.println("Processing ₹" + amount + " via Stripe");
    }

    @Override
    public String getProviderName() { return "Stripe"; }
}

class RazorpayProcessor extends PaymentProcessor {
    public RazorpayProcessor(String merchantId) { super(merchantId, 1.5); }

    @Override
    public void processPayment(double amount) {
        System.out.println("Processing ₹" + amount + " via Razorpay");
    }

    @Override
    public String getProviderName() { return "Razorpay"; }
}

public class App {
    public static void main(String[] args) {
        PaymentProcessor stripe = new StripeProcessor("MERCH-001");
        PaymentProcessor razorpay = new RazorpayProcessor("MERCH-001");

        stripe.processPayment(10000);
        stripe.printSummary(10000);

        razorpay.processPayment(10000);
        razorpay.printSummary(10000);
    }
}

