abstract class ReportGenerator {
    public final String generate(String title, String[] rows) {
        StringBuilder sb = new StringBuilder();
        sb.append(header(title)).append("\n");
        for (int i = 0; i < rows.length; i++) {
            sb.append(formatRow(i + 1, rows[i])).append("\n");
        }
        sb.append(footer());
        return sb.toString();
    }

    protected abstract String header(String title);
    protected abstract String formatRow(int i, String row);
    protected abstract String footer();
}

class NumberedReport extends ReportGenerator {
    @Override protected String header(String t) { return "== " + t + " =="; }
    @Override protected String formatRow(int i, String row) { return i + ". " + row; }
    @Override protected String footer() { return "--- End ---"; }
}

class BulletReport extends ReportGenerator {
    @Override protected String header(String t) { return "# " + t; }
    @Override protected String formatRow(int i, String row) { return "\u2022 " + row; }
    @Override protected String footer() { return "(end)"; }
}

public class App {
    public static void main(String[] args) {
        String[] items = {"Milk", "Eggs", "Bread"};
        System.out.println(new NumberedReport().generate("Groceries", items));
        System.out.println("---");
        System.out.println(new BulletReport().generate("Groceries", items));
    }
}

