abstract class GameCharacter {
    protected String name;
    protected int health;

    public GameCharacter(String name, int health) {
        this.name = name;
        this.health = health;
    }

    public abstract int attack();
    public abstract String specialAbility();

    public void takeDamage(int dmg) {
        health = Math.max(0, health - dmg);
        System.out.println(name + " takes " + dmg + " damage (health=" + health + ")");
    }

    public boolean isAlive() { return health > 0; }

    public final void takeTurn() {
        if (!isAlive()) {
            System.out.println(name + " is defeated");
            return;
        }
        System.out.print(name + " attacks for " + attack() + " damage!");
        if (health < 50) {
            System.out.println(" Special: " + specialAbility());
        } else {
            System.out.println();
        }
    }
}

class Warrior extends GameCharacter {
    public Warrior(String name, int health) { super(name, health); }
    @Override public int attack() { return 50; }
    @Override public String specialAbility() { return "Shield Bash"; }
}

class Mage extends GameCharacter {
    public Mage(String name, int health) { super(name, health); }
    @Override public int attack() { return 30; }
    @Override public String specialAbility() { return "Fireball"; }
}

public class App {
    public static void main(String[] args) {
        Warrior aisha = new Warrior("Aisha", 100);
        Mage raj = new Mage("Raj", 100);

        aisha.takeDamage(60);
        aisha.takeTurn();
        raj.takeTurn();
    }
}

import java.util.ArrayList;
import java.util.List;

abstract class AbstractPipeline {
    public final String[] run(String rawInput) {
        String[] records = extract(rawInput);
        List<String> results = new ArrayList<>();
        for (String record : records) {
            if (validate(record)) {
                results.add(transform(record));
            }
        }
        String[] output = results.toArray(new String[0]);
        summarize(output);
        return output;
    }

    protected abstract String[] extract(String raw);
    protected abstract boolean validate(String record);
    protected abstract String transform(String record);

    protected void summarize(String[] results) {
        System.out.println(java.util.Arrays.toString(results));
        System.out.println("Processed " + results.length + " records");
    }
}

class CSVPipeline extends AbstractPipeline {
    @Override protected String[] extract(String raw) { return raw.split(","); }
    @Override protected boolean validate(String record) { return !record.trim().isEmpty(); }
    @Override protected String transform(String record) { return record.trim().toUpperCase(); }
}

class NumberPipeline extends AbstractPipeline {
    @Override protected String[] extract(String raw) { return raw.split(" "); }
    @Override protected boolean validate(String record) {
        try { Double.parseDouble(record.trim()); return true; }
        catch (NumberFormatException e) { return false; }
    }
    @Override protected String transform(String record) {
        return String.valueOf((int)(Double.parseDouble(record.trim()) * 2));
    }
}

public class App {
    public static void main(String[] args) {
        new CSVPipeline().run("Aisha, Raj, Priya");
        new NumberPipeline().run("10 7 15");
    }
}
